module counter_8bit_sync_en(clk, rst, en, count);
    input clk;
    input rst;
    input en;
    output reg [7:0] count;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            count <= 8'b0;
        else if (en)
            count <= count + 1;
    end
endmodule
